import React, { useState, useMemo } from 'react';

// ============================================
// Design Tokens
// ============================================
const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
  },
  font: "'JetBrains Mono', monospace",
};

const varColors = ['#f472b6', '#38bdf8', '#a3e635'];
const varNames = ['x', 'y', 'z'];

// ============================================
// Jacobi Solver
// ============================================
function solveJacobi(A, b, maxIter) {
  const n = b.length;
  const history = [{ iteration: 0, x: new Array(n).fill(0) }];
  let x = new Array(n).fill(0);

  for (let iter = 0; iter < maxIter; iter++) {
    const xNew = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
      let sum = 0;
      for (let j = 0; j < n; j++) {
        if (i !== j) sum += A[i][j] * x[j];
      }
      xNew[i] = Math.round(((b[i] - sum) / A[i][i]) * 10000) / 10000;
    }
    x = [...xNew];
    history.push({ iteration: iter + 1, x: [...x] });
  }
  return history;
}

// ============================================
// Equation Display (Human Readable)
// ============================================
function EquationDisplay({ A, b, x, eqIdx, showSolving, n }) {
  // Calculate what this equation "wants" for its main variable
  let otherSum = 0;
  for (let j = 0; j < n; j++) {
    if (j !== eqIdx) otherSum += A[eqIdx][j] * x[j];
  }
  const wantsValue = (b[eqIdx] - otherSum) / A[eqIdx][eqIdx];
  const currentValue = x[eqIdx];
  const diff = Math.abs(wantsValue - currentValue);
  const isHappy = diff < 0.01;

  // Build the "other variables" text dynamically based on actual number of variables
  const otherVars = [];
  for (let j = 0; j < n; j++) {
    if (j !== eqIdx) {
      otherVars.push(varNames[j]);
    }
  }
  const otherVarsText = otherVars.length === 1 
    ? otherVars[0] 
    : otherVars.slice(0, -1).join(', ') + ' and ' + otherVars[otherVars.length - 1];

  return (
    <div style={{
      padding: '12px 16px',
      background: showSolving ? `${varColors[eqIdx]}15` : theme.colors.surface,
      borderRadius: '10px',
      border: `2px solid ${showSolving ? varColors[eqIdx] : theme.colors.border}`,
      transition: 'all 0.3s',
    }}>
      {/* The equation in words */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flexWrap: 'wrap', fontSize: '13px' }}>
        {A[eqIdx].map((coef, j) => (
          <React.Fragment key={j}>
            {j > 0 && <span style={{ color: theme.colors.textMuted }}>{coef >= 0 ? '+' : '−'}</span>}
            <span style={{ color: theme.colors.text }}>{j === 0 ? coef : Math.abs(coef)}</span>
            <span style={{ 
              color: varColors[j], 
              fontWeight: '700',
              padding: '2px 6px',
              background: `${varColors[j]}20`,
              borderRadius: '4px',
            }}>
              {varNames[j]}
            </span>
          </React.Fragment>
        ))}
        <span style={{ color: theme.colors.textMuted }}>=</span>
        <span style={{ color: theme.colors.green, fontWeight: '700' }}>{b[eqIdx]}</span>
      </div>

      {/* What this equation thinks */}
      {showSolving && (
        <div style={{
          marginTop: '10px',
          padding: '10px 12px',
          background: theme.colors.background,
          borderRadius: '8px',
          fontSize: '12px',
        }}>
          <div style={{ color: theme.colors.textSecondary, marginBottom: '6px' }}>
            💭 "If <span style={{ color: varColors[otherVars.map(v => varNames.indexOf(v))[0]] }}>{otherVarsText}</span> {otherVars.length === 1 ? 'is' : 'are'} correct, then..."
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
            <span style={{ color: varColors[eqIdx], fontWeight: '700' }}>{varNames[eqIdx]}</span>
            <span style={{ color: theme.colors.textMuted }}>should be</span>
            <span style={{
              padding: '4px 10px',
              background: `${varColors[eqIdx]}30`,
              borderRadius: '6px',
              color: varColors[eqIdx],
              fontWeight: '700',
            }}>
              {wantsValue.toFixed(4)}
            </span>
            {isHappy ? (
              <span style={{ color: theme.colors.positive }}>✓ Close!</span>
            ) : (
              <span style={{ color: theme.colors.yellow }}>↻ Adjusting...</span>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================
// Variable Status Cards
// ============================================
function VariableCards({ x, prevX }) {
  return (
    <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
      {x.map((val, i) => {
        const changed = prevX && Math.abs(val - prevX[i]) > 0.0001;
        const changeAmount = prevX ? val - prevX[i] : 0;

        return (
          <div key={i} style={{
            padding: '12px 16px',
            background: theme.colors.surface,
            borderRadius: '10px',
            border: `2px solid ${varColors[i]}`,
            textAlign: 'center',
            minWidth: '80px',
          }}>
            <div style={{
              fontSize: '18px',
              fontWeight: '700',
              color: varColors[i],
              marginBottom: '4px',
            }}>
              {varNames[i]}
            </div>
            <div style={{
              fontSize: '16px',
              fontWeight: '600',
              color: theme.colors.text,
            }}>
              {val.toFixed(3)}
            </div>
            {changed && (
              <div style={{
                fontSize: '10px',
                color: changeAmount > 0 ? theme.colors.positive : theme.colors.negative,
                marginTop: '4px',
              }}>
                {changeAmount > 0 ? '↑' : '↓'} {Math.abs(changeAmount).toFixed(3)}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ============================================
// Convergence Visualization
// ============================================
function ConvergenceViz({ history, currentStep }) {
  const visibleHistory = history.slice(0, currentStep + 1);
  const n = history[0].x.length;

  // Check if converged
  const isConverged = currentStep > 1 && history[currentStep].x.every((val, i) => 
    Math.abs(val - history[currentStep - 1].x[i]) < 0.001
  );

  return (
    <div style={{
      padding: '16px',
      background: theme.colors.surface,
      borderRadius: '10px',
    }}>
      <div style={{
        fontSize: '11px',
        color: theme.colors.textMuted,
        marginBottom: '12px',
        textAlign: 'center',
      }}>
        Watch the values stabilize over iterations
      </div>

      {/* Visual bars for each variable */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
        {Array.from({ length: n }).map((_, varIdx) => {
          const allVals = history.map(h => h.x[varIdx]);
          const minVal = Math.min(...allVals, 0);
          const maxVal = Math.max(...allVals);
          const range = maxVal - minVal || 1;

          return (
            <div key={varIdx}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' }}>
                <span style={{ color: varColors[varIdx], fontWeight: '700', fontSize: '12px', width: '20px' }}>
                  {varNames[varIdx]}
                </span>
                <div style={{
                  flex: 1,
                  height: '24px',
                  background: theme.colors.background,
                  borderRadius: '12px',
                  position: 'relative',
                  overflow: 'hidden',
                }}>
                  {/* Trail of previous values */}
                  {visibleHistory.map((h, i) => {
                    const pos = ((h.x[varIdx] - minVal) / range) * 100;
                    const isLatest = i === visibleHistory.length - 1;
                    return (
                      <div
                        key={i}
                        style={{
                          position: 'absolute',
                          left: `${pos}%`,
                          top: '50%',
                          transform: 'translate(-50%, -50%)',
                          width: isLatest ? '16px' : '8px',
                          height: isLatest ? '16px' : '8px',
                          borderRadius: '50%',
                          background: varColors[varIdx],
                          opacity: isLatest ? 1 : 0.3,
                          transition: 'all 0.3s',
                          border: isLatest ? '2px solid #fff' : 'none',
                        }}
                      />
                    );
                  })}
                </div>
                <span style={{ color: theme.colors.text, fontSize: '11px', width: '50px', textAlign: 'right' }}>
                  {visibleHistory[visibleHistory.length - 1]?.x[varIdx].toFixed(3)}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {isConverged && (
        <div style={{
          marginTop: '12px',
          padding: '10px',
          background: `${theme.colors.positive}20`,
          borderRadius: '8px',
          textAlign: 'center',
          color: theme.colors.positive,
          fontSize: '12px',
        }}>
          🎯 Converged! The values have stabilized.
        </div>
      )}
    </div>
  );
}

// ============================================
// Step Indicator
// ============================================
function StepIndicator({ step, total }) {
  return (
    <div style={{ display: 'flex', gap: '4px', justifyContent: 'center' }}>
      {Array.from({ length: total + 1 }).map((_, i) => (
        <div
          key={i}
          style={{
            width: i === step ? '24px' : '8px',
            height: '8px',
            borderRadius: '4px',
            background: i <= step ? theme.colors.primary : theme.colors.border,
            transition: 'all 0.3s',
          }}
        />
      ))}
    </div>
  );
}

