// Main App
// ============================================
export default function JacobiPlayground() {
  const [exampleIdx, setExampleIdx] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);

  const examples = [
    {
      name: '3 Variables',
      A: [[5, -2, 3], [-3, 9, 1], [2, -1, -7]],
      b: [-1, 2, 3],
      iterations: 6,
    },
    {
      name: '2 Variables',
      A: [[4, 1], [2, 3]],
      b: [1, 2],
      iterations: 8,
    },
  ];

  const ex = examples[exampleIdx];
  const history = useMemo(() => solveJacobi(ex.A, ex.b, ex.iterations), [exampleIdx]);
  const n = ex.A.length;

  const reset = () => { setStep(0); setPlaying(false); };
  const next = () => step < history.length - 1 && setStep(step + 1);
  const prev = () => step > 0 && setStep(step - 1);

  const auto = async () => {
    setPlaying(true);
    for (let s = step; s < history.length; s++) {
      setStep(s);
      await new Promise(r => setTimeout(r, 1000));
    }
    setPlaying(false);
  };

  const currentX = history[step].x;
  const prevX = step > 0 ? history[step - 1].x : null;

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      color: theme.colors.text,
      fontFamily: theme.font,
      padding: '16px',
    }}>
      <div style={{ maxWidth: '500px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '16px' }}>
          <h1 style={{ fontSize: '18px', fontWeight: '700', margin: 0 }}>Jacobi Method</h1>
          <p style={{ color: theme.colors.textSecondary, fontSize: '11px', marginTop: '4px' }}>
            Solve equations by iterative refinement
          </p>
        </div>

        {/* Example Tabs */}
        <div style={{ display: 'flex', gap: '8px', justifyContent: 'center', marginBottom: '16px' }}>
          {examples.map((e, idx) => (
            <button
              key={idx}
              onClick={() => { setExampleIdx(idx); reset(); }}
              style={{
                padding: '8px 16px',
                background: exampleIdx === idx ? theme.colors.primary : theme.colors.surface,
                border: 'none',
                borderRadius: '8px',
                color: exampleIdx === idx ? '#fff' : theme.colors.textSecondary,
                fontFamily: theme.font,
                fontSize: '12px',
                cursor: 'pointer',
              }}
            >
              {e.name}
            </button>
          ))}
        </div>

        {/* Main Card */}
        <div style={{ background: theme.colors.surfaceAlt, borderRadius: '12px', padding: '16px' }}>

          {/* The Idea */}
          {step === 0 && (
            <div style={{
              padding: '16px',
              background: `${theme.colors.primary}15`,
              borderRadius: '10px',
              marginBottom: '16px',
              borderLeft: `4px solid ${theme.colors.primary}`,
            }}>
              <div style={{ fontSize: '13px', color: theme.colors.text, marginBottom: '8px', fontWeight: '600' }}>
                💡 The Idea
              </div>
              <div style={{ fontSize: '12px', color: theme.colors.textSecondary, lineHeight: 1.6 }}>
                We have {n} equations with {n} unknowns. Each equation can tell us what ONE variable 
                should be — if we knew all the others. So we start with a guess, let each equation 
                "vote" on its variable, then repeat until everyone agrees!
              </div>
            </div>
          )}

          {/* Current Values */}
          <div style={{ marginBottom: '16px' }}>
            <div style={{ fontSize: '10px', color: theme.colors.textMuted, marginBottom: '8px', textAlign: 'center' }}>
              {step === 0 ? 'STARTING GUESS' : `AFTER ITERATION ${step}`}
            </div>
            <VariableCards x={currentX} prevX={prevX} />
          </div>

          {/* Convergence - NOW BEFORE EQUATIONS */}
          {step > 0 && (
            <div style={{ marginBottom: '16px' }}>
              <ConvergenceViz history={history} currentStep={step} />
            </div>
          )}

          {/* How it works explanation */}
          {step > 0 && step < 3 && (
            <div style={{
              padding: '12px',
              background: theme.colors.surface,
              borderRadius: '8px',
              marginBottom: '16px',
              fontSize: '11px',
              color: theme.colors.textSecondary,
              lineHeight: 1.6,
            }}>
              <strong style={{ color: theme.colors.yellow }}>What just happened?</strong>
              <br />
              Each equation looked at the current values of the OTHER variables, 
              then calculated what ITS variable should be. All updates happen 
              simultaneously using the OLD values — that's the Jacobi way!
            </div>
          )}

          {/* Equations - NOW AFTER CONVERGENCE */}
          <div style={{ marginBottom: '16px' }}>
            <div style={{ fontSize: '10px', color: theme.colors.textMuted, marginBottom: '8px', textAlign: 'center' }}>
              THE EQUATIONS
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              {ex.A.map((_, i) => (
                <EquationDisplay
                  key={i}
                  A={ex.A}
                  b={ex.b}
                  x={currentX}
                  eqIdx={i}
                  showSolving={step > 0}
                  n={n}
                />
              ))}
            </div>
          </div>

          {/* Step Indicator */}
          <div style={{ marginBottom: '16px' }}>
            <StepIndicator step={step} total={history.length - 1} />
          </div>

          {/* Controls */}
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <button onClick={prev} disabled={step <= 0} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: step <= 0 ? theme.colors.textMuted : theme.colors.text,
              cursor: step <= 0 ? 'not-allowed' : 'pointer',
              fontSize: '14px',
            }}>
              ←
            </button>

            <button onClick={next} disabled={step >= history.length - 1} style={{
              flex: 1,
              padding: '12px',
              background: step < history.length - 1 ? theme.colors.primary : theme.colors.positive,
              border: 'none',
              borderRadius: '8px',
              color: '#fff',
              fontFamily: theme.font,
              fontSize: '12px',
              fontWeight: '600',
              cursor: step < history.length - 1 ? 'pointer' : 'default',
            }}>
              {step === 0 ? '🚀 Start Iterating' : step < history.length - 1 ? 'Next Iteration →' : '✓ Complete!'}
            </button>

            <button onClick={auto} disabled={playing || step >= history.length - 1} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: playing || step >= history.length - 1 ? theme.colors.textMuted : theme.colors.text,
              cursor: playing || step >= history.length - 1 ? 'not-allowed' : 'pointer',
              fontSize: '12px',
            }}>
              ▶▶
            </button>

            <button onClick={reset} style={{
              padding: '10px 14px',
              background: theme.colors.surface,
              border: 'none',
              borderRadius: '8px',
              color: theme.colors.text,
              cursor: 'pointer',
              fontSize: '14px',
            }}>
              ↺
            </button>
          </div>
        </div>

        {/* Key Insight */}
        <div style={{
          marginTop: '12px',
          padding: '12px 16px',
          background: theme.colors.surface,
          borderRadius: '8px',
          fontSize: '11px',
          color: theme.colors.textSecondary,
          textAlign: 'center',
        }}>
          <strong style={{ color: theme.colors.text }}>Key insight:</strong> Each equation "adjusts" its variable based on the others. 
          Repeat until all equations are satisfied — that's when the values stop changing!
        </div>
      </div>
    </div>
  );
}

